// Wrap the makeDataFromStr function by one that adds the type/subtype in the options
// Ideally, the handlers would parse the string and select the correct handler to dispatch...
#define GenericHandlerTuple(which, type) TypeHandlersTuple{                                         \
    [](const std::string& str, const options_t& options, const TIVarFile* _ctx) -> data_t {         \
        options_t options_withType = options;                                                       \
        options_withType["_type"] = type;                                                           \
        return (TypeHandlers::TH_Generic##which::makeDataFromString)(str, options_withType, _ctx);  \
    },                                                                                              \
    &(TypeHandlers::TH_Generic##which::makeStringFromData),                                         \
    &(TypeHandlers::TH_Generic##which::getMinVersionFromData),                                      \
}
#define SettingsHandlerTuple(type) TypeHandlersTuple{                                               \
    [](const std::string& str, const options_t& options, const TIVarFile* _ctx) -> data_t {         \
        options_t options_withType = options;                                                       \
        options_withType["_type"] = type;                                                           \
        return (TypeHandlers::TH_Settings::makeDataFromString)(str, options_withType, _ctx);        \
    },                                                                                              \
    &(TypeHandlers::TH_Settings::makeStringFromData),                                               \
    &(TypeHandlers::TH_Settings::getMinVersionFromData),                                            \
}
#define StructuredAppVarHandlerTuple(subtype) TypeHandlersTuple{                                    \
    [](const std::string& str, const options_t& options, const TIVarFile* _ctx) -> data_t {         \
        options_t options_withSubtype = options;                                                    \
        options_withSubtype["_appvarSubtype"] = subtype;                                            \
        return (TypeHandlers::TH_StructuredAppVar::makeDataFromString)(str, options_withSubtype, _ctx); \
    },                                                                                              \
    &(TypeHandlers::TH_StructuredAppVar::makeStringFromData),                                       \
    &(TypeHandlers::TH_StructuredAppVar::getMinVersionFromData),                                    \
}

