    bool TIVarTypes::isValidID(uint8_t id)
    {
        ensure_types_initialized();
        return types.contains(std::to_string(id));
    }

    bool TIVarTypes::isValidName(const std::string& name)
    {
        ensure_types_initialized();
        return (!name.empty() && types.contains(name));
    }
