unsigned char hexdec(const std::string& str)
{
    return (unsigned char) stoul(str, nullptr, 16);
}

data_t hex_string_to_bytes(const std::string& hex, const char* fieldName)
{
    if ((hex.size() % 2) != 0)
    {
        throw std::invalid_argument(std::string(fieldName) + " must contain an even number of hex digits");
    }

    data_t out;
    out.reserve(hex.size() / 2);
    for (size_t i = 0; i < hex.size(); i += 2)
    {
        if (!std::isxdigit(static_cast<unsigned char>(hex[i])) ||
            !std::isxdigit(static_cast<unsigned char>(hex[i + 1])))
        {
            throw std::invalid_argument(std::string(fieldName) + " must be valid hexadecimal");
        }
        out.push_back(hexdec(hex.substr(i, 2)));
    }
    return out;
}

std::string dechex(unsigned char i, bool zeropad)
{
    std::string str = "00";
    snprintf(&str[0], 3, zeropad ? "%02X" : "%X", i);
    return str;
}

std::string strtoupper(const std::string& str)
{
    std::string newStr(str);
    for (char& c : newStr)
    {
        c = (char) toupper(c);
    }
    return newStr;
}

void replace_all(std::string& str, const std::string& from, const std::string& to)
{
    if (from.empty())
    {
        return;
    }

    for (size_t pos = 0; (pos = str.find(from, pos)) != std::string::npos; pos += to.size())
    {
        str.replace(pos, from.size(), to);
    }
}

std::vector<std::string> explode(const std::string& str, const std::string& delim)
{
    std::vector<std::string> result;

    size_t last = 0;
    size_t next = 0;
    while ((next = str.find(delim, last)) != std::string::npos)
    {
        result.push_back(str.substr(last, next - last));
        last = next + delim.length();
    }
    result.push_back(str.substr(last));

    return result;
}

std::vector<std::string> explode(const std::string& str, char delim)
{
    return explode(str, std::string(1, delim));
}

// trim from start
std::string ltrim(std::string s, const char* t)
{
    s.erase(0, s.find_first_not_of(t));
    return s;
}

// trim from end
std::string rtrim(std::string s, const char* t)
{
    s.erase(s.find_last_not_of(t) + 1);
    return s;
}

// trim from both ends
std::string trim(const std::string& s, const char* t)
{
    return ltrim(rtrim(s, t), t);
}

bool is_numeric(const std::string& str)
{
    char* p;
    const double ignored = strtod(str.c_str(), &p);
    (void)ignored;
    return !*p;
}

bool file_exists(const std::string& path) {
    if (path.empty()) {
        return false;
    }
    if (FILE *file = fopen(path.c_str(), "r")) {
        fclose(file);
        return true;
    } else {
        return false;
    }
}

std::string str_pad(const std::string& str, unsigned long pad_length, const std::string& pad_string)
{
    unsigned long i, x;
    const unsigned long str_size = str.size();
    const unsigned long pad_size = pad_string.size();

    if (pad_length <= str_size || pad_size < 1)
    {
        return str;
    }

    std::string o;
    o.reserve(pad_length);

    for (i = 0, x = str_size; i < x; i++)
    {
        o.push_back(str[i]);
    }
    for (i = str_size; i < pad_length;)
    {
        for (unsigned long j = 0; j < pad_size && i < pad_length; j++, i++)
        {
            o.push_back(pad_string[j]);
        }
    }

    return o;
}

std::string multiple(int num, const std::string &var)
{
    return multiple(static_cast<long long>(num), var);
}

std::string multiple(long long num, const std::string &var) {
    const std::string unit = var.empty() ? "1" : var;
    switch (num) {
        case 0:
            return "0";
        case 1:
            return unit;
        case -1:
            return "-" + unit;
        default:
            return std::to_string(num) + var;
    }
}

// Adapted from http://stackoverflow.com/a/32903747/378298
std::string dec2frac(double num, const std::string& var, double err)
{
    const auto decimal_fallback = [&](long double value) {
        return trimZeros(format_decimal_value_tivars_amalgamated_src__tivarslib_utils_cpp(value)) + var;
    };

    if (err <= 0.0 || err >= 1.0)
    {
        err = 0.001;
    }

    if (!std::isfinite(num))
    {
        return trimZeros(format_decimal_value_tivars_amalgamated_src__tivarslib_utils_cpp(num)) + var;
    }

    const int sign = ( num > 0 ) ? 1 : ( ( num < 0 ) ? -1 : 0 );

    if (sign == -1)
    {
        num = std::abs(num);
    }

    if (sign != 0)
    {
        // err is the maximum relative err; convert to absolute
        err *= num;
        err = std::max(err, std::numeric_limits<double>::epsilon());
    }

    if (num >= static_cast<double>(std::numeric_limits<long long>::max())
     || num <= static_cast<double>(std::numeric_limits<long long>::lowest()))
    {
        return decimal_fallback(static_cast<long double>(sign) * static_cast<long double>(num));
    }

    const long long n = static_cast<long long>(std::floor(num));
    num -= n;

    if (num < err)
    {
        return multiple(sign * n, var);
    }

    if (1 - err < num)
    {
        return multiple(sign * (n + 1), var);
    }

    // The lower fraction is 0/1
    long long lower_n = 0;
    long long lower_d = 1;

    // The upper fraction is 1/1
    long long upper_n = 1;
    long long upper_d = 1;

    long long max_denominator = dec2fracMaxDenominator_tivars_amalgamated_src__tivarslib_utils_cpp;
    const long double err_denominator_bound = std::ceil(1.0L / static_cast<long double>(err));
    if (std::isfinite(err_denominator_bound))
    {
        max_denominator = std::min<long long>(max_denominator, std::max<long long>(1, static_cast<long long>(err_denominator_bound)));
    }

    size_t iterations = 0;
    const size_t max_iterations = static_cast<size_t>(max_denominator) * 2;

    while (true)
    {
        if (++iterations > max_iterations)
        {
            return decimal_fallback(static_cast<long double>(sign) * (static_cast<long double>(n) + static_cast<long double>(num)));
        }

        // The middle fraction is (lower_n + upper_n) / (lower_d + upper_d)
        if (lower_n > std::numeric_limits<long long>::max() - upper_n
         || lower_d > std::numeric_limits<long long>::max() - upper_d)
        {
            return decimal_fallback(static_cast<long double>(sign) * (static_cast<long double>(n) + static_cast<long double>(num)));
        }

        const long long middle_n = lower_n + upper_n;
        const long long middle_d = lower_d + upper_d;
        if (middle_d > max_denominator)
        {
            return decimal_fallback(static_cast<long double>(sign) * (static_cast<long double>(n) + static_cast<long double>(num)));
        }

        if (static_cast<long double>(middle_d) * static_cast<long double>(num + err) < static_cast<long double>(middle_n))
        {
            // real + err < middle : middle is our new upper
            upper_n = middle_n;
            upper_d = middle_d;
        }
        else if (static_cast<long double>(middle_n) < static_cast<long double>(num - err) * static_cast<long double>(middle_d))
        {
            // middle < real - err : middle is our new lower
            lower_n = middle_n;
            lower_d = middle_d;
        } else {
            // Middle is our best fraction
            if (n != 0 && middle_d > std::numeric_limits<long long>::max() / std::llabs(n))
            {
                return decimal_fallback(static_cast<long double>(sign) * (static_cast<long double>(n) + static_cast<long double>(num)));
            }
            if (sign != 0 && std::llabs(n * middle_d + middle_n) > std::numeric_limits<long long>::max() / std::llabs(sign))
            {
                return decimal_fallback(static_cast<long double>(sign) * (static_cast<long double>(n) + static_cast<long double>(num)));
            }
            return multiple((n * middle_d + middle_n) * sign, var) + "/" + std::to_string(middle_d);
        }
    }
}

std::string trimZeros(const std::string& str)
{
    try
    {
        const long double value = std::stold(str);
        if (!std::isfinite(value))
        {
            return str;
        }

        std::string out = format_decimal_value_tivars_amalgamated_src__tivarslib_utils_cpp(value);
        if (out == "-0")
        {
            return "0";
        }
        return out;
    }
    catch (const std::exception&)
    {
        return str;
    }
}

std::string entry_name_to_string(const TIVarType& type, const uint8_t* nameBytes, size_t size)
{
    if (nameBytes == nullptr || size == 0)
    {
        return "";
    }

    const uint8_t first = nameBytes[0];
    const uint8_t second = size > 1 ? nameBytes[1] : 0x00;
    const uint8_t typeId = static_cast<uint8_t>(type.getId());

    const auto nulPos = static_cast<const uint8_t*>(memchr(nameBytes, '\0', size));
    const size_t asciiLen = nulPos ? static_cast<size_t>(nulPos - nameBytes) : size;
    const auto asciiString = [&]() {
        return std::string(reinterpret_cast<const char*>(nameBytes), asciiLen);
    };
    const auto tiNameBodyString = [](const uint8_t* bytes, size_t len) {
        std::string out;
        for (size_t i = 0; i < len; i++)
        {
            if (bytes[i] == 0x5B)
            {
                out += "θ";
            }
            else
            {
                out.push_back(static_cast<char>(bytes[i]));
            }
        }
        return out;
    };
    const auto printableAsciiString = [&]() {
        for (size_t i = 0; i < asciiLen; i++)
        {
            if (nameBytes[i] < 0x20 || nameBytes[i] > 0x7E)
            {
                return std::string();
            }
        }
        return asciiString();
    };
    const auto printableTINameString = [&]() {
        for (size_t i = 0; i < asciiLen; i++)
        {
            if (nameBytes[i] < 0x20 || nameBytes[i] > 0x7E)
            {
                return std::string();
            }
        }
        return tiNameBodyString(nameBytes, asciiLen);
    };
    const auto hasTINameCharacters = [&]() {
        switch (typeId)
        {
            case 0x05: // Program
            case 0x06: // ProtectedProgram
            case 0x15: // AppVar
            case 0x17: // GroupObject
            case 0x26: // AppIDList
                return true;
            default:
                return false;
        }
    };
    const auto validCustomListNameBody = [&]() {
        if (asciiLen == 0 || asciiLen > 5 || std::isdigit(static_cast<unsigned char>(nameBytes[0])))
        {
            return false;
        }
        for (size_t i = 0; i < asciiLen; i++)
        {
            const uint8_t c = nameBytes[i];
            if (!std::isdigit(c) && (c < 'A' || c > 'Z') && c != 0x5B)
            {
                return false;
            }
        }
        return true;
    };
    const auto canonicalize_equation_name = [&](uint8_t& outSecond) {
        if (first == 0x5E)
        {
            outSecond = second;
            return true;
        }
        if (first == 'r' && second >= 0x81 && second <= 0x86)
        {
            outSecond = static_cast<uint8_t>(0x40 + (second - 0x81));
            return true;
        }
        if (first == 'U')
        {
            outSecond = 0x80;
            return true;
        }
        if (first == 'V')
        {
            outSecond = 0x81;
            return true;
        }
        if (first == 'W')
        {
            outSecond = 0x82;
            return true;
        }
        if (first == 'X' && second >= 0x81 && second <= 0x86)
        {
            outSecond = static_cast<uint8_t>(0x20 + ((second - 0x81) * 2));
            return true;
        }
        if (first == 'Y' && second >= 0x81 && second <= 0x86)
        {
            outSecond = static_cast<uint8_t>(0x21 + ((second - 0x81) * 2));
            return true;
        }
        return false;
    };

    if ((typeId == 0x01 || typeId == 0x0D) && first == TypeHandlers::TH_GenericList::listNameMarker)
    {
        if (second <= 0x05)
        {
            return "L"s + static_cast<char>('1' + second);
        }
        if (second == 0x40)
        {
            return "IDList";
        }

        const auto listNulPos = static_cast<const uint8_t*>(memchr(nameBytes + 1, '\0', size - 1));
        const size_t listLen = listNulPos ? static_cast<size_t>(listNulPos - (nameBytes + 1)) : (size - 1);
        return tiNameBodyString(nameBytes + 1, listLen);
    }
    if ((typeId == 0x01 || typeId == 0x0D) && validCustomListNameBody())
    {
        return tiNameBodyString(nameBytes, asciiLen);
    }

    if (typeId == 0x02 && first == 0x5C && second <= 0x09)
    {
        return "["s + static_cast<char>('A' + second) + "]";
    }

    if (typeId == 0x03 || typeId == 0x0B)
    {
        uint8_t canonicalSecond = 0x00;
        if (!canonicalize_equation_name(canonicalSecond))
        {
            canonicalSecond = second;
        }

        if (canonicalSecond >= 0x10 && canonicalSecond <= 0x19)
        {
            const char digit = canonicalSecond == 0x19 ? '0' : static_cast<char>('1' + (canonicalSecond - 0x10));
            return "Y"s + digit;
        }
        if (canonicalSecond >= 0x20 && canonicalSecond <= 0x2B)
        {
            const uint8_t idx = static_cast<uint8_t>((canonicalSecond - 0x20) / 2);
            const char axis = (canonicalSecond % 2 == 0) ? 'X' : 'Y';
            return std::string(1, axis) + static_cast<char>('1' + idx) + "T";
        }
        if (canonicalSecond >= 0x40 && canonicalSecond <= 0x45)
        {
            return "R"s + static_cast<char>('1' + (canonicalSecond - 0x40));
        }
        if (canonicalSecond >= 0x80 && canonicalSecond <= 0x82)
        {
            return std::string(1, static_cast<char>('U' + (canonicalSecond - 0x80)));
        }
    }

    if (typeId == 0x04 && first == 0xAA)
    {
        const char digit = second == 9 ? '0' : static_cast<char>('1' + second);
        return "Str"s + digit;
    }

    if (typeId == 0x07 && first == 0x60)
    {
        const char digit = second == 9 ? '0' : static_cast<char>('1' + second);
        return "Pic"s + digit;
    }

    if (typeId == 0x08 && first == 0x61)
    {
        const char digit = second == 9 ? '0' : static_cast<char>('1' + second);
        return "GDB"s + digit;
    }

    if (typeId == 0x0F)
    {
        return "Window";
    }
    if (typeId == 0x10)
    {
        return "RclWindw";
    }
    if (typeId == 0x11)
    {
        return "TblSet";
    }

    if (typeId == 0x1A && first == 0x3C)
    {
        const char digit = second == 9 ? '0' : static_cast<char>('1' + second);
        return "Image"s + digit;
    }

    if (hasTINameCharacters())
    {
        return printableTINameString();
    }

    if (first >= 'A' && first <= 'Z')
    {
        return std::string(1, static_cast<char>(first));
    }
    if (first == 0x5B)
    {
        return "θ";
    }

    return printableAsciiString();
}

std::string sanitize_for_host_filename(const std::string& name)
{
    std::string sanitized(name);

    replace_all(sanitized, "", "T");
    replace_all(sanitized, "₀", "0");
    replace_all(sanitized, "₁", "1");
    replace_all(sanitized, "₂", "2");
    replace_all(sanitized, "₃", "3");
    replace_all(sanitized, "₄", "4");
    replace_all(sanitized, "₅", "5");
    replace_all(sanitized, "₆", "6");
    replace_all(sanitized, "₇", "7");
    replace_all(sanitized, "₈", "8");
    replace_all(sanitized, "₉", "9");
    replace_all(sanitized, "/", "_");

    return sanitized;
}

std::array<uint8_t, 3> rgb565_to_rgb888(uint16_t value)
{
    const uint8_t red5 = static_cast<uint8_t>((value >> 11) & 0x1F);
    const uint8_t green6 = static_cast<uint8_t>((value >> 5) & 0x3F);
    const uint8_t blue5 = static_cast<uint8_t>(value & 0x1F);

    return {
        static_cast<uint8_t>((red5 * 255 + 15) / 31),
        static_cast<uint8_t>((green6 * 255 + 31) / 63),
        static_cast<uint8_t>((blue5 * 255 + 15) / 31),
    };
}

std::string make_bmp_data_url_rgba(uint32_t width, uint32_t height, const data_t& rgbaPixels)
{
    if (width == 0 || height == 0)
    {
        return "";
    }

    const size_t expectedPixelBytes = static_cast<size_t>(width) * static_cast<size_t>(height) * 4;
    data_t normalized(expectedPixelBytes, 0x00);
    const size_t copyLen = std::min(expectedPixelBytes, rgbaPixels.size());
    std::copy(rgbaPixels.begin(), rgbaPixels.begin() + static_cast<ptrdiff_t>(copyLen), normalized.begin());

    for (size_t i = 3; i < normalized.size(); i += 4)
    {
        if (i >= copyLen)
        {
            normalized[i] = 0xFF;
        }
    }

    const uint32_t rowStride = width * 4U;
    const uint32_t pixelArraySize = rowStride * height;
    const uint32_t fileHeaderSize = 14;
    const uint32_t dibHeaderSize = 124;
    const uint32_t pixelOffset = fileHeaderSize + dibHeaderSize;
    const uint32_t fileSize = pixelOffset + pixelArraySize;

    data_t bmp;
    bmp.reserve(fileSize);
    bmp.push_back('B');
    bmp.push_back('M');
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, fileSize);
    append_le16_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 0);
    append_le16_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 0);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, pixelOffset);

    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, dibHeaderSize);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, width);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, height);
    append_le16_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 1);
    append_le16_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 32);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 3);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, pixelArraySize);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 2835);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 2835);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 0);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 0);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 0x00FF0000);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 0x0000FF00);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 0x000000FF);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 0xFF000000);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 0x73524742); // LCS_sRGB

    for (int i = 0; i < 9; i++)
    {
        append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 0);
    }
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 0);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 0);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 0);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 0); // intent
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 0); // profile data offset
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 0); // profile size
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 0); // reserved

    for (uint32_t row = 0; row < height; row++)
    {
        const uint32_t srcY = height - 1 - row;
        const size_t rowStart = static_cast<size_t>(srcY) * static_cast<size_t>(width) * 4;
        for (uint32_t x = 0; x < width; x++)
        {
            const size_t src = rowStart + static_cast<size_t>(x) * 4;
            bmp.push_back(normalized[src + 2]);
            bmp.push_back(normalized[src + 1]);
            bmp.push_back(normalized[src]);
            bmp.push_back(normalized[src + 3]);
        }
    }

    return "data:image/bmp;base64," + base64_encode_tivars_amalgamated_src__tivarslib_utils_cpp(bmp);
}

std::string make_bmp_data_url(uint32_t width, uint32_t height, const data_t& rgbPixels)
{
    if (width == 0 || height == 0)
    {
        return "";
    }

    const size_t expectedPixelBytes = static_cast<size_t>(width) * static_cast<size_t>(height) * 3;
    data_t normalized(expectedPixelBytes, 0xFF);
    const size_t copyLen = std::min(expectedPixelBytes, rgbPixels.size());
    std::copy(rgbPixels.begin(), rgbPixels.begin() + static_cast<ptrdiff_t>(copyLen), normalized.begin());

    const uint32_t rowStride = (width * 3U + 3U) & ~3U;
    const uint32_t pixelArraySize = rowStride * height;
    const uint32_t fileHeaderSize = 14;
    const uint32_t dibHeaderSize = 40;
    const uint32_t pixelOffset = fileHeaderSize + dibHeaderSize;
    const uint32_t fileSize = pixelOffset + pixelArraySize;

    data_t bmp;
    bmp.reserve(fileSize);
    bmp.push_back('B');
    bmp.push_back('M');
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, fileSize);
    append_le16_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 0);
    append_le16_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 0);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, pixelOffset);

    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, dibHeaderSize);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, width);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, height);
    append_le16_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 1);
    append_le16_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 24);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 0);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, pixelArraySize);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 2835);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 2835);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 0);
    append_le32_tivars_amalgamated_src__tivarslib_utils_cpp(bmp, 0);

    for (uint32_t row = 0; row < height; row++)
    {
        const uint32_t srcY = height - 1 - row;
        const size_t rowStart = static_cast<size_t>(srcY) * static_cast<size_t>(width) * 3;
        for (uint32_t x = 0; x < width; x++)
        {
            const size_t src = rowStart + static_cast<size_t>(x) * 3;
            bmp.push_back(normalized[src + 2]);
            bmp.push_back(normalized[src + 1]);
            bmp.push_back(normalized[src]);
        }
        while ((bmp.size() - pixelOffset) % rowStride != 0)
        {
            bmp.push_back(0x00);
        }
    }

    return "data:image/bmp;base64," + base64_encode_tivars_amalgamated_src__tivarslib_utils_cpp(bmp);
}

