        json split_lines_json_tivars_amalgamated_src__TypeHandlers__TH_StructuredAppVar_cpp(const std::string& text, char delim)
        {
            json lines = json::array();
            if (text.empty())
            {
                return lines;
            }

            size_t start = 0;
            while (true)
            {
                const size_t end = text.find(delim, start);
                if (end == std::string::npos)
                {
                    lines.push_back(text.substr(start));
                    break;
                }

                lines.push_back(text.substr(start, end - start));
                start = end + 1;
                if (start == text.size())
                {
                    lines.push_back("");
                    break;
                }
            }

            return lines;
        }

        std::string join_lines_tivars_amalgamated_src__TypeHandlers__TH_StructuredAppVar_cpp(const json& lines, char delim)
        {
            if (!lines.is_array())
            {
                throw std::invalid_argument("lines must be an array of strings");
            }

            std::string text;
            for (size_t i = 0; i < lines.size(); i++)
            {
                if (!lines[i].is_string())
                {
                    throw std::invalid_argument("lines must contain only strings");
                }
                if (i != 0)
                {
                    text.push_back(delim);
                }
                text += lines[i].get<std::string>();
            }
            return text;
        }

